parameters.jsonBody:
={
  "embeds": [
    {
      "title": "📅 NOUVEAU RDV PLANIFIÉ",
      "color": 3066993,
      "fields": [
        { "name": "🏢 Entreprise", "value": "{{ $json.body.business_name }}", "inline": false },
        { "name": "📍 Adresse", "value": "{{ $json.body.address }}", "inline": true },
        { "name": "🏙️ Ville", "value": "{{ $json.body.city }}", "inline": true },
        { "name": "📞 Téléphone", "value": "{{ $json.body.phone }}", "inline": true },
        { "name": "🔧 Secteur", "value": "{{ $json.body.sector }}", "inline": true },
        { "name": "📆 Date du RDV", "value": "{{ $json.body.appointment_date }}", "inline": true },
        { "name": "🕐 Heure", "value": "{{ $json.body.appointment_time }}", "inline": true },
        { "name": "📝 Notes", "value": "{{ $json.body.notes || 'Aucune' }}", "inline": false },
        { "name": "👤 Qualifié par", "value": "{{ $json.body.agent_name }}", "inline": false }
      ],
      "footer": { "text": "Merci de confirmer la prise en charge avec un ✅" },
      "timestamp": "{{ $json.body.timestamp }}"
    }
  ]
}
